import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ValentineDay = 
  | 'Rose Day'
  | 'Propose Day'
  | 'Chocolate Day'
  | 'Teddy Day'
  | 'Promise Day'
  | 'Hug Day'
  | 'Kiss Day'
  | 'Valentine’s Day';

export interface TimelineEvent {
  id: string;
  date: string;
  title: string;
  description: string;
}

export interface LovePage {
  id: string;
  userId?: string;
  day: ValentineDay;
  title: string;
  message: string;
  isSecret: boolean;
  mediaUrl?: string;
  templateId: string;
  giftGifId?: string;
  effects: string[];
  timeline: TimelineEvent[];
  isPublished: boolean;
  publishedAt?: number;
  lastEdited?: number;
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  avatar: string;
  isPro: boolean;
  proExpiry?: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const getAIPolish = async (text: string, mood: string = 'romantic') => {
  if (!API_KEY) return text;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an emotional ghostwriter for Lovia, a Valentine's app. 
      Rewrite this message to be more ${mood}, poetic, and heartwarming. 
      Keep it personal and concise. 
      Message: "${text}"`,
    });
    return response.text || text;
  } catch (error) {
    console.error("AI polishing failed", error);
    return text;
  }
};

export const generateTimelineSuggestions = async (day: string) => {
  if (!API_KEY) return [];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 3 romantic milestone ideas for a relationship timeline for ${day}. 
      Keep titles short and descriptions cute.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["title", "description"]
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("AI timeline failed", error);
    return [];
  }
};

import React, { useMemo } from 'react';
