import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeft, 
  Sparkles, 
  Image as ImageIcon, 
  Plus, 
  Eye, 
  Send,
  Wand2,
  Trash2,
  Lock
} from 'lucide-react';
import { ValentineDay, LovePage, TimelineEvent } from '../types';
import { TEMPLATES, EFFECTS, GIF_IDS } from '../constants';
import { getAIPolish, generateTimelineSuggestions } from '../services/geminiService';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro }) => {
  const [step, setStep] = useState(1);
  const [pageData, setPageData] = useState<LovePage>({
    id: Math.random().toString(36).substr(2, 9),
    day: initialDay,
    title: `My Special ${initialDay}`,
    message: '',
    isSecret: false,
    templateId: 't1',
    effects: [],
    timeline: [],
    isPublished: false,
  });

  const [aiLoading, setAiLoading] = useState(false);

  const updatePage = (updates: Partial<LovePage>) => {
    setPageData(prev => ({ ...prev, ...updates }));
  };

  const handleAIPolish = async () => {
    if (!pageData.message) return;
    setAiLoading(true);
    const polished = await getAIPolish(pageData.message);
    updatePage({ message: polished });
    setAiLoading(false);
  };

  const addTimelineEvent = () => {
    const newEvent: TimelineEvent = {
      id: Math.random().toString(36).substr(2, 5),
      date: new Date().toLocaleDateString(),
      title: 'Our Special Moment',
      description: 'Describe what happened...'
    };
    updatePage({ timeline: [...pageData.timeline, newEvent] });
  };

  const toggleEffect = (id: string) => {
    const isAlreadyAdded = pageData.effects.includes(id);
    if (isAlreadyAdded) {
      updatePage({ effects: pageData.effects.filter(e => e !== id) });
    } else {
      if (pageData.effects.length >= 3) return; // Max 3 effects rule
      updatePage({ effects: [...pageData.effects, id] });
    }
  };

  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const steps = [
    "The Title",
    "Your Message",
    "Special Sections",
    "Templates & Gifts",
    "Review & Publish"
  ];

  return (
    <div className="pt-24 pb-32 px-4 max-w-4xl mx-auto z-10 relative">
      <button 
        onClick={onBack}
        className="mb-6 flex items-center gap-2 text-gray-500 hover:text-pink-500 transition-colors font-semibold"
      >
        <ArrowLeft className="w-5 h-5" />
        <span>Back to Home</span>
      </button>

      <div className="bg-white rounded-[2.5rem] shadow-xl border border-pink-50 p-6 md:p-10">
        {/* Step Indicator */}
        <div className="flex items-center justify-between mb-10 overflow-x-auto pb-2">
          {steps.map((label, idx) => (
            <div key={label} className="flex items-center">
              <div className={`flex flex-col items-center gap-2 min-w-[80px]`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${step === idx + 1 ? 'bg-pink-400 text-white shadow-lg shadow-pink-200' : 'bg-pink-50 text-pink-300'}`}>
                  {idx + 1}
                </div>
                <span className={`text-[10px] font-bold uppercase tracking-widest ${step === idx + 1 ? 'text-pink-500' : 'text-gray-300'}`}>{label}</span>
              </div>
              {idx < steps.length - 1 && <div className="w-8 h-[2px] bg-pink-50 mx-2 mb-6" />}
            </div>
          ))}
        </div>

        <AnimatePresence mode="wait">
          <motion.div
            key={step}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            className="min-h-[400px]"
          >
            {step === 1 && (
              <div className="space-y-6">
                <h2 className="text-3xl font-bold text-gray-800">Set the tone... ✍️</h2>
                <div className="space-y-4">
                  <label className="block text-sm font-bold text-gray-400 uppercase tracking-wider">Page Title</label>
                  <input 
                    type="text"
                    value={pageData.title}
                    onChange={e => updatePage({ title: e.target.value })}
                    className="w-full p-4 bg-pink-50 border-2 border-transparent focus:border-pink-200 rounded-2xl outline-none text-xl font-semibold text-gray-700 transition-all"
                    placeholder="E.g., For My Sunshine..."
                  />
                  <div className="flex flex-wrap gap-2">
                    {["Love letter for you", "To my favorite person", "Happy Valentine's"].map(t => (
                      <button 
                        key={t}
                        onClick={() => updatePage({ title: t })}
                        className="px-4 py-2 bg-white border border-pink-100 rounded-full text-sm text-pink-500 hover:bg-pink-50"
                      >
                        {t}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-3xl font-bold text-gray-800">Your Heart's Voice ❤️</h2>
                  <button 
                    onClick={handleAIPolish}
                    disabled={aiLoading}
                    className="flex items-center gap-2 px-4 py-2 bg-purple-100 text-purple-600 rounded-full font-bold text-sm hover:bg-purple-200 disabled:opacity-50 transition-all"
                  >
                    <Wand2 className={`w-4 h-4 ${aiLoading ? 'animate-spin' : ''}`} />
                    {aiLoading ? 'Polishing...' : 'AI Polish'}
                  </button>
                </div>
                <textarea 
                  value={pageData.message}
                  onChange={e => updatePage({ message: e.target.value })}
                  rows={8}
                  className="w-full p-6 bg-cream/30 border-2 border-pink-50 rounded-[2rem] outline-none text-lg text-gray-700 leading-relaxed transition-all focus:bg-white focus:shadow-inner"
                  placeholder="Write your beautiful message here... Let your emotions flow."
                />
                <p className="text-sm text-gray-400 italic text-center">In Story Mode, your message will reveal line-by-line magically.</p>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-8">
                <h2 className="text-3xl font-bold text-gray-800">Add Magic ✨</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <button 
                    onClick={addTimelineEvent}
                    className="p-6 border-2 border-dashed border-pink-200 rounded-3xl flex flex-col items-center gap-2 text-pink-500 hover:bg-pink-50 transition-all group"
                  >
                    <Plus className="w-8 h-8 group-hover:rotate-90 transition-transform" />
                    <span className="font-bold">Add Timeline Milestone</span>
                    <span className="text-xs opacity-60">Memorable dates from your story</span>
                  </button>

                  <div className={`p-6 border-2 border-dashed rounded-3xl flex flex-col items-center gap-2 transition-all ${pageData.isSecret ? 'bg-pink-400 text-white border-pink-400' : 'border-purple-200 text-purple-500 hover:bg-purple-50'}`}>
                    {(!isPro && !pageData.isSecret) ? (
                      <div className="flex flex-col items-center gap-2">
                        <Lock className="w-8 h-8 opacity-40" />
                        <span className="font-bold">Secret Surprise</span>
                        <span className="text-xs opacity-60">PRO only feature</span>
                        <button className="mt-2 text-[10px] underline uppercase tracking-widest font-bold">Unlock PRO</button>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center gap-2 cursor-pointer" onClick={() => updatePage({ isSecret: !pageData.isSecret })}>
                         <Sparkles className="w-8 h-8" />
                         <span className="font-bold">{pageData.isSecret ? 'Secret Enabled' : 'Add Hidden Surprise'}</span>
                         <span className="text-xs opacity-80">Message starts blurred</span>
                      </div>
                    )}
                  </div>
                </div>

                {pageData.timeline.length > 0 && (
                  <div className="space-y-4">
                    <h3 className="font-bold text-gray-500 text-xs uppercase tracking-widest">Your Timeline</h3>
                    {pageData.timeline.map((event, idx) => (
                      <div key={event.id} className="bg-pink-50/50 p-4 rounded-2xl flex items-start gap-4">
                        <div className="flex-1 space-y-2">
                          <input 
                            className="bg-transparent font-bold w-full outline-none text-gray-700" 
                            value={event.title}
                            onChange={(e) => {
                              const newTimeline = [...pageData.timeline];
                              newTimeline[idx].title = e.target.value;
                              updatePage({ timeline: newTimeline });
                            }}
                          />
                          <input 
                            className="bg-transparent text-sm w-full outline-none text-gray-500" 
                            value={event.description}
                            onChange={(e) => {
                              const newTimeline = [...pageData.timeline];
                              newTimeline[idx].description = e.target.value;
                              updatePage({ timeline: newTimeline });
                            }}
                          />
                        </div>
                        <button 
                          onClick={() => updatePage({ timeline: pageData.timeline.filter(e => e.id !== event.id) })}
                          className="text-pink-300 hover:text-pink-500"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {step === 4 && (
              <div className="space-y-10">
                <section className="space-y-4">
                  <h3 className="text-xl font-bold text-gray-800">Visual Templates</h3>
                  <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                    {TEMPLATES.map(t => (
                      <button
                        key={t.id}
                        onClick={() => (isPro || !t.isPro) && updatePage({ templateId: t.id })}
                        className={`relative p-4 rounded-2xl border-2 transition-all text-center flex flex-col items-center gap-2 ${pageData.templateId === t.id ? 'border-pink-400 bg-pink-50 text-pink-500' : 'border-gray-50 bg-white text-gray-400 hover:border-pink-100'}`}
                      >
                        <div className="w-full h-12 bg-gray-100 rounded-lg flex items-center justify-center">
                          <ImageIcon className="w-5 h-5 opacity-20" />
                        </div>
                        <span className="text-[10px] font-bold uppercase">{t.name}</span>
                        {t.isPro && !isPro && <Lock className="absolute top-2 right-2 w-3 h-3 text-pink-300" />}
                      </button>
                    ))}
                  </div>
                </section>

                <section className="space-y-4">
                  <h3 className="text-xl font-bold text-gray-800">Magical Effects (Max 3)</h3>
                  <div className="flex flex-wrap gap-2">
                    {EFFECTS.map(e => (
                      <button
                        key={e.id}
                        onClick={() => (isPro || !e.isPro) && toggleEffect(e.id)}
                        className={`px-4 py-2 rounded-full text-sm font-semibold transition-all flex items-center gap-2 ${pageData.effects.includes(e.id) ? 'bg-pink-400 text-white shadow-md' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                      >
                        {e.isPro && !isPro && <Lock className="w-3 h-3" />}
                        {e.name}
                      </button>
                    ))}
                  </div>
                </section>

                <section className="space-y-4">
                   <h3 className="text-xl font-bold text-gray-800">Cinematic GIF</h3>
                   <div className="grid grid-cols-3 sm:grid-cols-6 gap-2">
                     {GIF_IDS.slice(0, 12).map((id, idx) => (
                       <button
                         key={id}
                         onClick={() => updatePage({ giftGifId: id })}
                         className={`aspect-square rounded-xl overflow-hidden border-4 transition-all ${pageData.giftGifId === id ? 'border-pink-400' : 'border-transparent opacity-60 hover:opacity-100'}`}
                       >
                         <img src={`https://media.tenor.com/${id}/tenor.gif`} className="w-full h-full object-cover" alt="gift" />
                       </button>
                     ))}
                   </div>
                </section>
              </div>
            )}

            {step === 5 && (
              <div className="text-center space-y-8">
                <div className="w-24 h-24 bg-pink-100 rounded-full flex items-center justify-center text-pink-500 mx-auto animate-bounce">
                  <Send className="w-10 h-10" />
                </div>
                <div className="space-y-2">
                  <h2 className="text-3xl font-bold text-gray-800">Ready to share the love?</h2>
                  <p className="text-gray-500">Your masterpiece is ready. You can still edit it after publishing if you have PRO.</p>
                </div>

                <div className="bg-cream/40 p-6 rounded-3xl border border-pink-100 text-left max-w-sm mx-auto">
                   <div className="flex items-center gap-3 mb-4">
                     <div className="w-10 h-10 bg-pink-400 rounded-xl flex items-center justify-center text-white">
                        <Sparkles className="w-5 h-5" />
                     </div>
                     <div>
                       <h4 className="font-bold text-gray-700">{pageData.title}</h4>
                       <span className="text-xs text-pink-400 font-bold uppercase">{pageData.day}</span>
                     </div>
                   </div>
                   <p className="text-sm text-gray-500 line-clamp-2">"{pageData.message}"</p>
                </div>
              </div>
            )}
          </motion.div>
        </AnimatePresence>

        {/* Navigation Buttons */}
        <div className="flex items-center justify-between mt-12 pt-8 border-t border-pink-50">
          <button 
            onClick={prevStep}
            disabled={step === 1}
            className={`px-6 py-3 font-bold transition-all ${step === 1 ? 'opacity-0' : 'text-gray-400 hover:text-pink-400'}`}
          >
            Previous
          </button>

          <div className="flex items-center gap-3">
            <button 
              className="px-6 py-3 flex items-center gap-2 text-pink-500 font-bold hover:bg-pink-50 rounded-2xl transition-all"
            >
              <Eye className="w-5 h-5" />
              <span>Preview</span>
            </button>
            {step < 5 ? (
              <button 
                onClick={nextStep}
                className="px-8 py-3 bg-pink-400 text-white rounded-2xl font-bold hover:bg-pink-500 transition-all shadow-lg shadow-pink-100"
              >
                Continue
              </button>
            ) : (
              <button 
                onClick={() => onPublish(pageData)}
                className="px-10 py-3 bg-pink-500 text-white rounded-2xl font-bold hover:bg-pink-600 transition-all shadow-lg shadow-pink-200"
              >
                Publish Now 💕
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Builder;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Heart, Lock, ChevronDown } from 'lucide-react';
import { LovePage } from '../types';

interface PreviewProps {
  page: LovePage;
}

const Preview: React.FC<PreviewProps> = ({ page }) => {
  const [showContent, setShowContent] = useState(false);
  const [revealedLines, setRevealedLines] = useState<string[]>([]);
  const [unlocked, setUnlocked] = useState(!page.isSecret);
  const [isFinished, setIsFinished] = useState(false);

  const lines = page.message.split('\n').filter(l => l.trim() !== '');

  useEffect(() => {
    // Reveal lines one by one after a short intro
    if (showContent && unlocked) {
      let currentLine = 0;
      const interval = setInterval(() => {
        if (currentLine < lines.length) {
          setRevealedLines(prev => [...prev, lines[currentLine]]);
          currentLine++;
        } else {
          clearInterval(interval);
          setTimeout(() => setIsFinished(true), 1000);
        }
      }, 1500); // Emotional timing: 1.5s per line
      return () => clearInterval(interval);
    }
  }, [showContent, unlocked, lines.length]);

  return (
    <div className="min-h-screen relative flex flex-col items-center justify-center p-6 text-center overflow-x-hidden">
      {/* Background Layer (Template Specific) */}
      <div className={`fixed inset-0 z-[-1] transition-colors duration-1000 ${page.templateId === 'p4' ? 'bg-gray-900' : 'bg-[#FFFDF9]'}`} />

      {/* Effects Layer */}
      {page.effects.map(effectId => (
         <div key={effectId} className="fixed inset-0 pointer-events-none z-[5] opacity-50">
           {/* Here we would render the specific particle system or overlay */}
         </div>
      ))}

      {/* Intro Phase */}
      {!showContent && (
        <motion.div 
          className="flex flex-col items-center gap-6"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          <motion.div 
            className="w-24 h-24 bg-pink-100 rounded-full flex items-center justify-center text-pink-500"
            animate={{ scale: [1, 1.1, 1] }}
            transition={{ duration: 2, repeat: Infinity }}
          >
            <Heart className="w-12 h-12 fill-current" />
          </motion.div>
          <div className="space-y-2">
            <h1 className="text-3xl font-bold text-gray-800 font-quicksand">Someone loves you...</h1>
            <p className="text-gray-400">Click to reveal your Valentine moment</p>
          </div>
          <button 
            onClick={() => setShowContent(true)}
            className="mt-4 px-10 py-4 bg-pink-400 text-white rounded-full font-bold shadow-xl shadow-pink-200"
          >
            Open Letter
          </button>
        </motion.div>
      )}

      {/* Content Phase */}
      {showContent && (
        <div className="max-w-xl w-full flex flex-col items-center z-10 py-20">
          {/* Title Reveal */}
          <motion.h2 
            className="text-2xl md:text-4xl font-bold text-pink-500 mb-2 font-quicksand"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 1 }}
          >
            {page.title}
          </motion.h2>
          <motion.div 
            className="text-xs font-bold uppercase tracking-widest text-pink-200 mb-12"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.5 }}
          >
            {page.day}
          </motion.div>

          {/* Secret Message Lock */}
          {!unlocked ? (
            <motion.div 
              className="bg-white/40 backdrop-blur-md p-10 rounded-[3rem] border border-white/60 shadow-2xl flex flex-col items-center gap-6"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
            >
              <div className="w-16 h-16 bg-pink-50 rounded-full flex items-center justify-center text-pink-400">
                <Lock className="w-8 h-8" />
              </div>
              <div className="space-y-2">
                <h3 className="text-xl font-bold text-gray-700">A Secret Surprise...</h3>
