              {/* Message Reveal */}
              <div className="space-y-6 mb-12">
                {revealedLines.map((line, idx) => (
                  <motion.p 
                    key={idx}
                    className="text-xl md:text-2xl text-gray-700 leading-relaxed font-nunito italic"
                    initial={{ opacity: 0, filter: 'blur(10px)', y: 10 }}
                    animate={{ opacity: 1, filter: 'blur(0px)', y: 0 }}
                    transition={{ duration: 1 }}
                  >
                    {line}
                  </motion.p>
                ))}
              </div>

              {/* Gift/GIF Reveal */}
              {isFinished && page.giftGifId && (
                <motion.div 
                  className="w-full aspect-square max-w-[300px] mx-auto rounded-3xl overflow-hidden shadow-2xl border-8 border-white"
                  initial={{ opacity: 0, scale: 0.5, rotate: -10 }}
