import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeft, 
  Sparkles, 
  Image as ImageIcon, 
  Plus, 
  Eye, 
  Send,
  Wand2,
  Trash2,
  Lock,
  ChevronRight,
  Sparkle,
  Camera,
  Play,
  CheckCircle2,
  XCircle
} from 'lucide-react';
import { ValentineDay, LovePage, TimelineEvent } from '../types';
import { TEMPLATES, EFFECTS, GIF_IDS } from '../constants';
import { getAIPolish, getMessageSuggestions, getTitleSuggestions } from '../services/geminiService';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [step, setStep] = useState(1);
  const [pageData, setPageData] = useState<LovePage>({
    id: Math.random().toString(36).substr(2, 9),
    day: initialDay,
    title: `My Special ${initialDay}`,
    message: '',
    isSecret: false,
    templateId: 't1',
    effects: [],
    timeline: [],
    isPublished: false,
    adUnlocks: {}
  });

  const [aiLoading, setAiLoading] = useState(false);
  const [helperOpen, setHelperOpen] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [titleSuggestions, setTitleSuggestions] = useState<string[]>([]);
  const [selectedMood, setSelectedMood] = useState<string | null>(null);
  const [previewGif, setPreviewGif] = useState<string | null>(null);

  // Monetization Modal State
  const [monetizationModal, setMonetizationModal] = useState<{ 
    open: boolean; 
    featureId: string; 
    type: 'ad' | 'pro' | 'both'; 
    adCountNeeded?: number 
  }>({ open: false, featureId: '', type: 'pro' });

  const updatePage = (updates: Partial<LovePage>) => {
    setPageData(prev => ({ ...prev, ...updates }));
  };

  const checkAccess = (featureId: string, itemIsPro: boolean, adCount: number = 1) => {
    if (isPro) return true;
    if (!itemIsPro) return true;
    const expiry = pageData.adUnlocks?.[featureId];
    if (expiry && expiry > Date.now()) return true;

    setMonetizationModal({ 
      open: true, 
      featureId, 
      type: adCount > 0 ? 'both' : 'pro', 
      adCountNeeded: adCount 
    });
    return false;
  };

  const handleWatchAd = (featureId: string) => {
    // Simulated Ad Watch: 2s delay
    setAiLoading(true);
    setTimeout(() => {
      const expiry = Date.now() + (24 * 60 * 60 * 1000); // 24h
      updatePage({
        adUnlocks: {
          ...(pageData.adUnlocks || {}),
          [featureId]: expiry
        }
      });
      setMonetizationModal({ ...monetizationModal, open: false });
      setAiLoading(false);
    }, 2000);
  };

  // ISSUE 1: AI Title Generator
  const handleSuggestTitle = async () => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_title', type: 'pro' });
      return;
    }
    setAiLoading(true);
    const results = await getTitleSuggestions(pageData.day, pageData.message);
    setTitleSuggestions(results);
    setAiLoading(false);
  };

  // ISSUE 2: Optimized AI Polish
  const handleAIPolish = async () => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_polish', type: 'pro' });
      return;
    }
    if (!pageData.message) return;
    setAiLoading(true);
    const polished = await getAIPolish(pageData.message);
    updatePage({ message: polished });
    setAiLoading(false);
  };

  const fetchSuggestions = async (mood: string) => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_helper', type: 'pro' });
      return;
    }
    setSelectedMood(mood);
    setAiLoading(true);
    const results = await getMessageSuggestions(mood, isPro);
    setSuggestions(results);
    setAiLoading(false);
  };

  // ISSUE 3: Timeline Photos & Limits
  const addTimelineEvent = () => {
    const freeLimit = 3;
    const currentCount = pageData.timeline.length;

    if (!isPro && currentCount >= freeLimit) {
      const unlockKey = `timeline_extra_${currentCount + 1}`;
      if (!checkAccess(unlockKey, true, 1)) return;
    }

    const newEvent: TimelineEvent = {
      id: Math.random().toString(36).substr(2, 5),
      date: new Date().toLocaleDateString(),
      title: 'A Beautiful Moment',
      description: 'Describe your memory...'
    };
    updatePage({ timeline: [...pageData.timeline, newEvent] });
  };

  const handlePhotoUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newTimeline = [...pageData.timeline];
        newTimeline[index].photoUrl = reader.result as string;
        updatePage({ timeline: newTimeline });
      };
      reader.readAsDataURL(file);
    }
  };

  // ISSUE 6: Effects logic (Max 3)
  const toggleEffect = (id: string, itemIsPro: boolean) => {
    if (!checkAccess(`effect_${id}`, itemIsPro, 1)) return;

    const isAlreadyAdded = pageData.effects.includes(id);
    if (isAlreadyAdded) {
      updatePage({ effects: pageData.effects.filter(e => e !== id) });
    } else {
      let newEffects = [...pageData.effects, id];
      if (newEffects.length > 3) {
        newEffects.shift(); // Auto-disable oldest
      }
      updatePage({ effects: newEffects });
    }
  };

  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const steps = ["Title", "Message", "Story", "Style", "Ready"];
  const moods = [
    { id: 'cute', label: 'Cute', color: 'bg-orange-50 text-orange-600' },
    { id: 'romantic', label: 'Romantic', color: 'bg-pink-50 text-pink-600' },
    { id: 'emotional', label: 'Emotional', color: 'bg-blue-50 text-blue-600' },
    { id: 'deep', label: 'Deep', color: 'bg-purple-50 text-purple-600' }
  ];

  return (
    <div className="pt-24 pb-32 px-4 max-w-4xl mx-auto z-10 relative">
      <button 
        onClick={onBack}
        className="mb-6 flex items-center gap-2 text-gray-500 hover:text-pink-500 transition-colors font-semibold"
      >
        <ArrowLeft className="w-5 h-5" />
        <span>Back to Home</span>
      </button>

      <div className="bg-white rounded-[2.5rem] shadow-xl border border-pink-50 p-6 md:p-10 relative overflow-hidden">
        {/* Subtle Loader */}
        <AnimatePresence>
          {aiLoading && (
            <motion.div 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 1 }} 
              exit={{ opacity: 0 }}
              className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex flex-col items-center justify-center gap-4"
            >
              <div className="w-16 h-16 border-4 border-pink-100 border-t-pink-400 rounded-full animate-spin" />
              <p className="font-bold text-pink-500 animate-pulse">Thinking with love... 💗</p>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Step Indicator */}
        <div className="flex items-center justify-between mb-10 overflow-x-auto pb-2">
          {steps.map((label, idx) => (
            <div key={label} className="flex items-center">
              <div className={`flex flex-col items-center gap-2 min-w-[70px]`}>
                <div className={`w-7 h-7 rounded-full flex items-center justify-center font-bold text-xs ${step === idx + 1 ? 'bg-pink-400 text-white' : 'bg-pink-50 text-pink-300'}`}>
                  {idx + 1}
                </div>
                <span className={`text-[9px] font-bold uppercase tracking-widest ${step === idx + 1 ? 'text-pink-500' : 'text-gray-300'}`}>{label}</span>
              </div>
              {idx < steps.length - 1 && <div className="w-6 h-[1px] bg-pink-50 mx-2 mb-4" />}
            </div>
          ))}
        </div>

        <AnimatePresence mode="wait">
          <motion.div
            key={step}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            className="min-h-[420px]"
          >
            {step === 1 && (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-3xl font-bold text-gray-800">Set the tone... ✍️</h2>
                  <button 
                    onClick={handleSuggestTitle}
                    className="flex items-center gap-2 px-4 py-2 bg-pink-50 text-pink-600 rounded-full font-bold text-sm hover:bg-pink-100 transition-all group"
                  >
                    <Sparkles className="w-4 h-4 group-hover:rotate-12" />
                    <span>Suggest Title</span>
                  </button>
                </div>

                <div className="space-y-4">
                  <input 
                    type="text"
                    value={pageData.title}
                    onChange={e => updatePage({ title: e.target.value })}
                    className="w-full p-5 bg-pink-50/50 border-2 border-transparent focus:border-pink-200 rounded-3xl outline-none text-2xl font-semibold text-gray-700 transition-all"
                    placeholder="E.g., For My Sunshine..."
                  />

                  {titleSuggestions.length > 0 && (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mt-4 animate-in fade-in slide-in-from-top-2">
                      {titleSuggestions.map((t, i) => (
                        <button 
                          key={i}
                          onClick={() => { updatePage({ title: t }); setTitleSuggestions([]); }}
                          className="text-left p-4 bg-white border border-pink-100 rounded-2xl hover:bg-pink-50 transition-all text-gray-600 font-medium"
                        >
                          {t}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-3xl font-bold text-gray-800">Your Message ❤️</h2>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => setHelperOpen(!helperOpen)}
                      className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold text-sm transition-all ${helperOpen ? 'bg-pink-400 text-white' : 'bg-pink-50 text-pink-600 hover:bg-pink-100'}`}
                    >
                      <Sparkles className="w-4 h-4" />
                      <span>{helperOpen ? 'Close' : 'Helper'}</span>
                    </button>
                    <button 
                      onClick={handleAIPolish}
                      disabled={!pageData.message}
                      className="flex items-center gap-2 px-4 py-2 bg-purple-50 text-purple-600 rounded-full font-bold text-sm hover:bg-purple-100 disabled:opacity-50 transition-all"
                    >
                      <Wand2 className="w-4 h-4" />
                      <span>Polish</span>
                    </button>
                  </div>
                </div>

                <AnimatePresence>
                  {helperOpen && (
                    <motion.div 
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: 'auto', opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      className="overflow-hidden space-y-4 bg-gray-50/80 p-6 rounded-3xl border border-gray-100"
                    >
                      <div className="flex flex-wrap gap-2">
                        {moods.map(mood => (
                          <button
                            key={mood.id}
                            onClick={() => fetchSuggestions(mood.id)}
                            className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${selectedMood === mood.id ? mood.color + ' shadow-sm' : 'bg-white text-gray-400 hover:text-pink-500'}`}
                          >
                            {mood.label}
                          </button>
                        ))}
                      </div>

                      {!aiLoading && suggestions.length > 0 && (
                        <div className="grid grid-cols-1 gap-2">
                          {suggestions.map((s, i) => (
                            <button
                              key={i}
                              onClick={() => { updatePage({ message: s }); setHelperOpen(false); }}
                              className="text-left p-4 bg-white rounded-2xl border border-gray-100 hover:border-pink-200 transition-all group"
                            >
                              <p className="text-xs text-gray-600 italic leading-relaxed">"{s}"</p>
                            </button>
                          ))}
                        </div>
                      )}
                    </motion.div>
                  )}
                </AnimatePresence>

                <textarea 
                  value={pageData.message}
                  onChange={e => updatePage({ message: e.target.value })}
                  rows={8}
                  className="w-full p-6 bg-cream/10 border-2 border-pink-50 rounded-[2.5rem] outline-none text-lg text-gray-700 leading-relaxed transition-all focus:bg-white focus:border-pink-100"
                  placeholder="Tell them how you truly feel..."
                />
              </div>
            )}

            {step === 3 && (
              <div className="space-y-8">
                <h2 className="text-3xl font-bold text-gray-800">Your Story ✨</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <button 
                    onClick={addTimelineEvent}
                    className="p-8 border-2 border-dashed border-pink-100 rounded-3xl flex flex-col items-center gap-2 text-pink-400 hover:bg-pink-50 hover:border-pink-300 transition-all group"
                  >
                    <Plus className="w-8 h-8 group-hover:rotate-90 transition-transform" />
                    <span className="font-bold">Add Milestone</span>
                    <span className="text-[10px] opacity-60 uppercase tracking-widest font-bold">
                      {isPro ? 'Unlimited' : `${3 - pageData.timeline.length} Slots Left`}
                    </span>
                  </button>

                  <div className={`p-8 border-2 border-dashed rounded-3xl flex flex-col items-center gap-2 transition-all cursor-pointer ${pageData.isSecret ? 'bg-pink-500 text-white border-pink-500 shadow-lg shadow-pink-100' : 'border-purple-100 text-purple-400 hover:bg-purple-50'}`}
                    onClick={() => {
                      if(checkAccess('hidden_surprise', true, 1)) {
                        updatePage({ isSecret: !pageData.isSecret });
                      }
                    }}
                  >
                    {pageData.isSecret ? <CheckCircle2 className="w-8 h-8" /> : <Lock className="w-8 h-8" />}
                    <span className="font-bold">{pageData.isSecret ? 'Surprise Enabled' : 'Hidden Surprise'}</span>
                    <span className="text-[10px] opacity-80 uppercase tracking-widest font-bold">Blurred until tap</span>
                  </div>
                </div>

                {pageData.timeline.length > 0 && (
                  <div className="space-y-6 pt-4">
                    {pageData.timeline.map((event, idx) => (
                      <div key={event.id} className="bg-white p-6 rounded-[2rem] border border-pink-50 shadow-sm flex flex-col md:flex-row gap-6 relative group">
                        <div className="w-full md:w-32 h-32 bg-pink-50 rounded-2xl flex-shrink-0 overflow-hidden border-2 border-white shadow-inner relative group/photo">
                          {event.photoUrl ? (
                            <img src={event.photoUrl} className="w-full h-full object-cover" alt="Milestone" />
                          ) : (
                            <div className="w-full h-full flex flex-col items-center justify-center text-pink-300">
                              <Camera className="w-6 h-6 mb-1" />
                              <span className="text-[8px] font-bold uppercase">Add Photo</span>
                            </div>
                          )}
                          <input 
                            type="file" 
                            accept="image/*"
                            className="absolute inset-0 opacity-0 cursor-pointer"
                            onChange={(e) => handlePhotoUpload(idx, e)}
                          />
                        </div>
                        <div className="flex-1 space-y-3">
                          <input 
                            className="bg-transparent font-bold w-full outline-none text-gray-800 text-lg border-b border-transparent focus:border-pink-100" 
                            value={event.title}
                            onChange={(e) => {
                              const newTimeline = [...pageData.timeline];
                              newTimeline[idx].title = e.target.value;
                              updatePage({ timeline: newTimeline });
                            }}
                          />
                          <textarea 
                            className="bg-transparent text-sm w-full outline-none text-gray-500 resize-none" 
                            rows={2}
                            value={event.description}
                            onChange={(e) => {
                              const newTimeline = [...pageData.timeline];
                              newTimeline[idx].description = e.target.value;
                              updatePage({ timeline: newTimeline });
                            }}
                          />
                          <div className="flex items-center gap-2">
                            <span className="text-[10px] font-bold text-pink-300 uppercase tracking-widest">Date:</span>
                            <input 
                              type="text"
                              className="bg-transparent text-[10px] font-bold text-gray-400 uppercase tracking-widest outline-none"
                              value={event.date}
                              onChange={(e) => {
                                const newTimeline = [...pageData.timeline];
                                newTimeline[idx].date = e.target.value;
                                updatePage({ timeline: newTimeline });
                              }}
                            />
                          </div>
                        </div>
                        <button 
                          onClick={() => updatePage({ timeline: pageData.timeline.filter(e => e.id !== event.id) })}
                          className="absolute top-4 right-4 text-pink-100 hover:text-pink-400 transition-colors"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {step === 4 && (
              <div className="space-y-12">
                <section className="space-y-6">
                  <div className="flex items-center justify-between">
                    <h3 className="text-xl font-bold text-gray-800">Visual Templates</h3>
                    <span className="text-[10px] bg-pink-50 text-pink-400 px-3 py-1 rounded-full font-bold uppercase tracking-widest">Live Preview</span>
                  </div>
                  <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                    {TEMPLATES.map(t => (
                      <button
                        key={t.id}
                        onClick={() => checkAccess(`template_${t.id}`, t.isPro, 1) && updatePage({ templateId: t.id })}
                        className={`relative p-5 rounded-3xl border-2 transition-all flex flex-col items-center gap-3 ${pageData.templateId === t.id ? 'border-pink-400 bg-pink-50 shadow-lg shadow-pink-100 scale-[1.05]' : 'border-gray-50 bg-white text-gray-400 hover:border-pink-100'}`}
                      >
                        <div className={`w-full h-12 rounded-xl flex items-center justify-center ${pageData.templateId === t.id ? 'bg-pink-100' : 'bg-gray-50'}`}>
                          <ImageIcon className={`w-5 h-5 ${pageData.templateId === t.id ? 'text-pink-400' : 'opacity-20'}`} />
                        </div>
                        <span className={`text-[9px] font-bold uppercase tracking-wider ${pageData.templateId === t.id ? 'text-pink-500' : ''}`}>{t.name}</span>
                        {t.isPro && !isPro && !pageData.adUnlocks?.[`template_${t.id}`] && <Lock className="absolute top-3 right-3 w-3 h-3 text-pink-200" />}
                      </button>
                    ))}
                  </div>
                </section>

                <section className="space-y-6">
                  <div className="flex items-center justify-between">
                    <h3 className="text-xl font-bold text-gray-800">Magical Effects</h3>
                    <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Max 3 Active</span>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {EFFECTS.map(e => (
                      <button
                        key={e.id}
                        onClick={() => toggleEffect(e.id, e.isPro)}
                        className={`px-6 py-3 rounded-2xl text-xs font-bold transition-all flex items-center gap-2 ${pageData.effects.includes(e.id) ? 'bg-pink-500 text-white shadow-xl shadow-pink-100' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}
                      >
                        {e.isPro && !isPro && !pageData.adUnlocks?.[`effect_${e.id}`] && <Lock className="w-3 h-3" />}
                        {e.name}
                        {pageData.effects.includes(e.id) && <CheckCircle2 className="w-3 h-3 ml-1" />}
                      </button>
                    ))}
                  </div>
                </section>

                <section className="space-y-6">
                   <div className="flex items-center justify-between">
                     <h3 className="text-xl font-bold text-gray-800">Cinematic GIF</h3>
                     <span className="text-[10px] text-pink-400 font-bold uppercase tracking-widest">Reveals at the End</span>
                   </div>
                   <div className="grid grid-cols-3 sm:grid-cols-6 gap-3">
                     {GIF_IDS.slice(0, 12).map((id) => (
                       <button
                         key={id}
                         onMouseEnter={() => setPreviewGif(id)}
                         onMouseLeave={() => setPreviewGif(null)}
                         onClick={() => {
                           if (checkAccess('gif_unlocked', true, 2)) {
                             updatePage({ giftGifId: id });
                           }
                         }}
                         className={`aspect-square rounded-2xl overflow-hidden border-4 transition-all relative group ${pageData.giftGifId === id ? 'border-pink-400 shadow-xl' : 'border-transparent opacity-70 hover:opacity-100 hover:scale-110'}`}
                       >
                         <img 
                           src={previewGif === id || pageData.giftGifId === id 
                              ? `https://media.tenor.com/${id}/tenor.gif` 
                              : `https://media.tenor.com/${id}/tenor.gif?itemid=${id}&type=static`
                           } 
                           className="w-full h-full object-cover" 
                           alt="gift" 
                         />
                         {pageData.giftGifId === id && (
                           <div className="absolute inset-0 bg-pink-500/20 flex items-center justify-center">
                             <Play className="w-6 h-6 text-white fill-current" />
                           </div>
                         )}
                         <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <Lock className="w-4 h-4 text-white drop-shadow-md" />
                         </div>
                       </button>
                     ))}
                   </div>
                </section>
              </div>
            )}

            {step === 5 && (
              <div className="text-center space-y-12 py-10">
                <div className="relative inline-block">
                  <div className="w-32 h-32 bg-pink-100 rounded-[2.5rem] flex items-center justify-center text-pink-500 mx-auto animate-bounce shadow-2xl shadow-pink-100">
                    <Send className="w-14 h-14" />
                  </div>
                  <motion.div 
                    animate={{ scale: [1, 1.2, 1], opacity: [0.5, 1, 0.5] }}
                    transition={{ repeat: Infinity, duration: 2 }}
                    className="absolute -top-4 -right-4 w-12 h-12 bg-white rounded-full flex items-center justify-center text-pink-400 shadow-lg"
                  >
                    <Sparkles className="w-6 h-6" />
                  </motion.div>
                </div>

                <div className="space-y-4">
                  <h2 className="text-4xl font-bold text-gray-800">Your Love is Ready! ❤️</h2>
                  <p className="text-gray-500 max-w-sm mx-auto leading-relaxed font-medium">Click publish to generate your private link and a custom QR code for your special someone.</p>
                </div>

                <div className="bg-pink-50/50 p-8 rounded-[3rem] border border-pink-100 text-left max-w-sm mx-auto shadow-inner">
                   <div className="flex items-center gap-4 mb-6">
                     <div className="w-14 h-14 bg-pink-400 rounded-3xl flex items-center justify-center text-white shadow-lg">
                        <Heart className="w-7 h-7 fill-current" />
                     </div>
                     <div>
                       <h4 className="font-bold text-gray-800 text-lg">{pageData.title}</h4>
                       <span className="text-[10px] text-pink-500 font-bold uppercase tracking-[0.2em]">{pageData.day}</span>
                     </div>
                   </div>
                   <p className="text-gray-500 italic leading-relaxed line-clamp-3">"{pageData.message}"</p>
                </div>
              </div>
            )}
          </motion.div>
        </AnimatePresence>

        {/* Navigation Buttons */}
        <div className="flex items-center justify-between mt-12 pt-10 border-t border-pink-50 relative z-10">
          <button 
            onClick={prevStep}
            disabled={step === 1}
            className={`px-8 py-4 font-bold transition-all text-sm uppercase tracking-widest ${step === 1 ? 'opacity-0' : 'text-gray-400 hover:text-pink-400'}`}
          >
            Back
          </button>

          <div className="flex items-center gap-4">
            <button 
              className="px-8 py-4 flex items-center gap-3 text-pink-500 font-bold hover:bg-pink-50 rounded-3xl transition-all text-sm uppercase tracking-widest"
            >
              <Eye className="w-5 h-5" />
              <span>Preview</span>
            </button>
            {step < 5 ? (
              <button 
                onClick={nextStep}
