    return [];
  }
};

/**
 * Suggests romantic timeline milestones using structured JSON output.
 */
export const generateTimelineSuggestions = async (day: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 3 romantic milestone ideas for a relationship timeline for ${day}. 
      Keep titles short and descriptions cute.`,
      config: {
        responseMimeType: "application/json",
