interface PreviewProps {
  page: LovePage;
  onBack?: () => void;
  isPro: boolean;
}

const Preview: React.FC<PreviewProps> = ({ page, onBack, isPro }) => {
  const [showContent, setShowContent] = useState(false);
  const [revealedLines, setRevealedLines] = useState<string[]>([]);
  const [unlocked, setUnlocked] = useState(!page.isSecret);
  const [isFinished, setIsFinished] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const lines = page.message.split('\n').filter(l => l.trim() !== '');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (showContent && unlocked) {
      let currentLine = 0;
      const interval = setInterval(() => {
        if (currentLine < lines.length) {
          setRevealedLines(prev => [...prev, lines[currentLine]]);
          currentLine++;
          // Auto-scroll to bottom as text reveals
          window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
        } else {
          clearInterval(interval);
          setTimeout(() => {
            setIsFinished(true);
            window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
          }, 800);
        }
      }, 1800); // Cinematic emotional timing
      return () => clearInterval(interval);
    }
  }, [showContent, unlocked, lines.length]);

  const handleShare = async () => {
    const url = window.location.href;
    if (navigator.share) {
      try {
        await navigator.share({
          title: page.title,
          text: `Check out this special ${page.day} message for you!`,
          url: url,
        });
      } catch (err) {
        setShowShareModal(true);
      }
    } else {
      setShowShareModal(true);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(window.location.href);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
