         <motion.div 
           className="fixed bottom-10 left-1/2 -translate-x-1/2 opacity-40 z-50 pointer-events-none"
           animate={{ y: [0, 10, 0] }}
           transition={{ repeat: Infinity, duration: 1.5 }}
         >
           <ChevronDown className="w-8 h-8" />
         </motion.div>
      )}
    </div>
  );
};

export default Preview;
